/**
 * Figma-exported icons used on the PlatformHome composer.
 *
 * Source: figma file ISS9k28oUIFlgfHq89i9xA, node 324:27443 (输入框).
 * Each icon was downloaded as raw SVG via the figma MCP. To match
 * figma's intent, every icon is rendered in a 16×16 viewBox with
 * `<g transform="translate(X Y)">` positioning the original path at
 * figma's exact inset within that box — this preserves the small
 * relative size of icons like chevron-down (9.33×5.33 in a 16-box).
 *
 * Icons accept `size` (px, default 16) and an optional `className`.
 * Paths use `fill="currentColor"` so the parent's text colour applies
 * — except `MessageAiIcon`, which carries the figma brand gradient
 * (orange → blue → magenta) as its visual identity.
 */

interface IconProps {
  size?: number
  className?: string
}

/** Tab icons gain `gradient` — when true the path(s) fill with the AI
 *  brand gradient (orange → blue → magenta) used to highlight the
 *  currently-selected project-type tab on PlatformHome. */
interface TabIconProps extends IconProps {
  gradient?: boolean
}

/** Shared <defs> for the AI brand gradient. Inlined into each tab
 *  icon's SVG when `gradient` is on; each icon scopes its own `id`
 *  to avoid cross-instance collision. */
function AiBrandGradient({ id }: { id: string }) {
  return (
    <defs>
      <linearGradient
        id={id}
        x1="0.0793688"
        y1="1.90486"
        x2="21.7288"
        y2="15.9422"
        gradientUnits="userSpaceOnUse"
      >
        <stop offset="0.163096" stopColor="#FFB31E" />
        <stop offset="0.530654" stopColor="#4397FF" />
        <stop offset="1" stopColor="#E135F8" />
      </linearGradient>
    </defs>
  )
}

